// 三载体一致:输出 PDF Blob;硬依赖 jsPDF
import { jsPDF } from 'https://cdn.jsdelivr.net/npm/jspdf@4/+esm';
import { svg2pdf } from 'https://cdn.jsdelivr.net/npm/svg2pdf.js@2/+esm';
// 待转 SVG 必须在渲染 DOM 中(靠 getBBox 量文本);纯字符串先解析
const svgEl = data.svgElement ?? new DOMParser().parseFromString(data.svgMarkup, 'image/svg+xml').documentElement;
if (!svgEl.isConnected) document.body.appendChild(svgEl); // widget 内改挂 shadowRoot
const pdf = new jsPDF({ unit: 'pt', format: 'a4' });
await svg2pdf(svgEl, pdf, { x: data.x ?? 0, y: data.y ?? 0, width: data.width, height: data.height });
const blob = pdf.output('blob'); // 或 pdf.save('out.pdf')
